import React, { useEffect, useRef, useState } from 'react'
import { useNavigate } from 'react-router-dom';
import { CCol, CForm, CButton, CFormLabel, CFormSelect, CFormCheck } from "@coreui/react";
import Select from "react-select";
import TagsInput from "react-tagsinput";
import "react-tagsinput/react-tagsinput.css";
import FormInput from 'src/utils/FormInput';
import UploadFiles from 'src/utils/UploadFiles';
import { getEnableCategory } from 'src/components/services/CategoryApi';
import { uploadAttachmentFile } from 'src/components/services/UploadAttachmentApi';
import { createTrivia, getTriviaDataById, updateTrivia } from 'src/components/services/TriviaApi';
import { getRelatedBlogByCategory } from 'src/components/services/BlogApi';
import { getRelatedInfograpicByCategory } from 'src/components/services/InfrograpicApi';
import TextArea from 'src/utils/TextArea';
import GoBackComponent from 'src/utils/GoBackComponent';

const TriviaForm = (props) => {
  const { type, id } = props;

  const [formData, setFormData] = useState({ title: "", metaTitle: "", metaDescription: "", metaImageAlt: "" });
  const [coverImage, setCoverImage] = useState("");
  const [tags, setTags] = useState([]);
  const [metaKeyWords, setMetaKeywords] = useState([]);
  const [errors, setErrors] = useState({});
  const [category, setCategory] = useState({});
  const [attachmentInfos, setAttachmentInfos] = useState([]);
  const [isButtonDisabled, setIsButtonDisabled] = useState(false);
  const [attachmentList, setAttachmentList] = useState([]);
  const [categoryOption, setCategoryOption] = useState([]);
  const [blogOption, setBlogOption] = useState([]);
  const [infographicOption, setInfographicOption] = useState([]);
  const [relatedBlog, setRelatedBlog] = useState([]);
  const [relatedInfographic, setRelatedInfographic] = useState([]);

  const uploadAddAttachmentsRef = useRef();

  const navigate = useNavigate();

  const handleChange = (event) => {
    setFormData({ ...formData, [event.target.name]: event.target.value.trimStart().replace(/  +/g, ' ') });
    console.log("formData", formData);
  };

  const tagsChange = (tag) => {
    setTags(tag);
  }

  const metaTagsChange = (tag) => {
    setMetaKeywords(tag);
  }

  const onClickUploadAttachment = () => {
    uploadAddAttachmentsRef.current.click();
  }

  const uploadCoverImage = (attachment) => {
    setCoverImage(attachment);
  }

  const removeAttachment = (id) => {
    let index = attachmentList && attachmentList.findIndex((data) => data._id === id);
    if (index > -1) {
      setAttachmentList([
        ...attachmentList.slice(0, index),
        ...attachmentList.slice(index + 1)
      ]);
    }
  }

  const uploadAddAttachments = (e) => {
    let errors = {};
    let maxFileSize = 2 * 1024 * 1024;
    let _progressInfos = attachmentInfos;
    _progressInfos = _progressInfos ? _progressInfos : []
    let promises = []
    if (e.target.files && e.target.files.length > 0) {
      for (let i = 0; i < e.target.files.length; i++) {
        let fileSize = e.target.files[i].size;
        if (fileSize > maxFileSize) {
          errors['attachments'] = "Please upload the file less than 2MB";
          setErrors(errors);
          document.getElementById('addAttachmentsFileUploader').value = null;
        } else {
          const fileName = document.getElementById('addAttachmentsFileUploader').value;
          const idxDot = fileName.lastIndexOf(".") + 1;
          const extFile = fileName.substr(idxDot, fileName.length).toLowerCase();
          const allowedAttachmentsTypeArr = ['jpg', 'jpeg', 'png'];
          _progressInfos.push({
            size: e.target.files[i].size,
            fileName: e.target.files[i].name,
            attachmentUrl: URL.createObjectURL(e.target.files[i]),
          });
          setAttachmentInfos(_progressInfos);
          if (allowedAttachmentsTypeArr.includes(extFile)) {
            promises.push(uploadAttachmentsFile(e.target.files[i]))
          } else {
            errors['attachments'] = 'Only ' + allowedAttachmentsTypeArr.join("/") + ' files are allowed!';
            setErrors(errors);
            document.getElementById('addAttachmentsFileUploader').value = null;
            setAttachmentInfos([]);
          }
        }
      }
    }
    setTimeout(() => {
      setErrors('');
    }, 5000);
  }

  const uploadAttachmentsFile = async (currentFile) => {
    setIsButtonDisabled(true);
    const formData = new FormData();
    formData.append("image", currentFile);
    let response = await uploadAttachmentFile(formData);
    if (response?.code === 200) {
      let data = response?.results;
      setAttachmentList(current => [...current, data]);
    }
    setIsButtonDisabled(false);
  }

  const handleChangeCategory = (data, type) => {
    if (type === "INFOGRAPIC") {
      setRelatedInfographic(data);
    } else if (type === "BLOG") {
      setRelatedBlog(data);
    } else {
      setCategory(data);
      setRelatedBlog([]);
      setRelatedInfographic([]);
      setBlogOption([]);
      setInfographicOption([]);
      getBlogOptionData(data.value);
      getInfograpicOptionData(data.value);
    }
  }

  const getInfograpicOptionData = async (id, relatedInfographics) => {
    let response = await getRelatedInfograpicByCategory(id);
    if (response?.code === 200) {
      response?.results && response?.results.map((data) => {
        setInfographicOption(current => [...current, { label: data.name, value: data.id }]);
      })
      if (type === "UPDATE") {
        var filteredArray = response?.results && response?.results.filter(function (n) { return relatedInfographics && relatedInfographics.indexOf(n.id) !== -1; });
        filteredArray && filteredArray.map((data) => { setRelatedInfographic(current => [...current, { label: data.name, value: data.id }]); });
      }
    }
  }

  const getBlogOptionData = async (id, relatedBlogs) => {
    let response = await getRelatedBlogByCategory(id);
    if (response?.code === 200) {
      response?.results && response?.results.map((data) => {
        setBlogOption(current => [...current, { label: data.name, value: data.id }]);
      })
      if (type === "UPDATE") {
        var filteredArray = response?.results && response?.results.filter(function (n) { return relatedBlogs && relatedBlogs.indexOf(n.id) !== -1; });
        filteredArray && filteredArray.map((data) => { setRelatedBlog(current => [...current, { label: data.name, value: data.id }]); })
      }
    }
  }

  const validateForm = () => {
    let errors = {};
    let formIsValid = true;
    if (!formData.title) {
      errors['title'] = "Please enter title";
      formIsValid = false;
    }
    if (!coverImage) {
      errors['coverImage'] = "Please add cover image";
      formIsValid = false;
    }
    if (!category?.value) {
      errors['category'] = "Please enter category";
      formIsValid = false;
    }
    if (attachmentList?.length === 0) {
      errors['attachments'] = "Please upload atleast one attachment";
      formIsValid = false;
    }
    if (tags?.length === 0) {
      errors['tags'] = "Please enter at least one tags";
      formIsValid = false;
    }
    if(!formData?.metaTitle) {
      errors['metaTitle'] = "Please enter meta title";
      formIsValid = false;
    }
    if(!formData?.metaDescription) {
      errors['metaDescription'] = "Please enter meta description";
      formIsValid = false;
    }
    if(!formData?.metaImageAlt) {
      errors['metaImageAlt'] = "Please enter meta image alt";
      formIsValid = false;
    }
    if (metaKeyWords?.length === 0) {
      errors['metaKeyWords'] = "Please enter at least one meta keywords";
      formIsValid = false;
    }
    setErrors(errors);
    setTimeout(() => {
      setErrors({});
    }, 2000);
    return formIsValid;
  }


  const fetchTriviaDataById = async (id, categories) => {
    let response = await getTriviaDataById(id);
    if (response?.code === 200 && response?.results != null) {
      let result = response?.results?.data
      let category = categories && categories.find((data) => data.value === result.category);
      setFormData({
        ...formData, title: result?.title, metaTitle: result?.metaTitle, metaDescription: result?.metaDescription, metaImageAlt: result?.metaImageAlt
      });
      setCategory(category);
      setCoverImage(response?.results?.coverImage);
      setTags(result.tags);
      setMetaKeywords(result?.metaKeyWords);
      //setAttachmentInfos(response?.results?.attachment);
      setAttachmentList(response?.results?.attachment);
      getInfograpicOptionData(result.category, result?.relatedInfograpics);
      getBlogOptionData(result.category, result?.relatedBlogs);
    }
  }

  const handleSubmit = async (event) => {
    event.preventDefault();
    if (validateForm()) {
      let relatedBlogs = [];
      let relatedInfographics = [];
      let imageUrlList = [];
      relatedBlog && relatedBlog.map((item) => {
        relatedBlogs.push(item.value)
      })
      relatedInfographic && relatedInfographic.map((item) => {
        relatedInfographics.push(item.value)
      })
      attachmentList && attachmentList.map((data) => {
        imageUrlList.push(data._id)
      })
      let data = {
        title: formData?.title?.trim(),
        metaTitle: formData?.metaTitle?.trim(),
        metaDescription: formData?.metaDescription?.trim(),
        metaKeyWords: metaKeyWords,
        metaImageAlt: formData?.metaImageAlt,
        category: category?.value,
        coverImageUrl: coverImage?._id,
        imageUrl: imageUrlList,
        tags: tags,
        relatedInfograpics: relatedInfographics,
        relatedBlogs: relatedBlogs
      };
      let teams = {};
      if (type === "CREATE") {
        teams = await createTrivia(data);
      }
      else {
        teams = await updateTrivia(props.id, data);
      }
      if (teams?.code === 201 || teams?.code === 202) {
        navigate('/trivia');
      }
    }
  };

  const getCategory = async () => {
    let categories = [];
    let response = await getEnableCategory();
    if (response?.code === 200) {
      response?.results && response?.results.map((data) => {
        categories.push({ label: data.name, value: data._id })
      })
      setCategoryOption(categories);
      if (props.type === "UPDATE") {
        fetchTriviaDataById(props.id, categories);
      }
    }
  }

  useEffect(() => {
    getCategory();
  }, [])

  return (
    <>
    <GoBackComponent goBackData={"trivia"} />
      <div className='customContainer'>
        <CForm className="row g-3">
          <UploadFiles
            id={"blogCoverImage"}
            accept=".jpg,.png,.jpeg"
            label="Cover Image"
            updateImage={coverImage?.imageUrl}
            updateFilesCb={uploadCoverImage}
          />
          <span style={{ color: "red", textAlign: "center" }}>{errors['coverImage']}</span>
          <CCol md={12}>
            <FormInput
              value={formData.title}
              label={"Title"}
              name={"title"}
              onChange={handleChange}
              required={true}
              error={errors['title']}
            />
          </CCol>
          <CCol md={6}>
            <div className='form-group'>
              <CFormLabel> Select Category <span className="text-danger">*</span></CFormLabel>
              <Select
                placeholder={"Select type"}
                className="wnforSelect"
                name={"userFilterOption"}
                options={categoryOption}
                value={category}
                onChange={handleChangeCategory}
                classNamePrefix="select"
                styles={{
                    option: (styles, { data, isDisabled, isFocused, isSelected }) => {
                        const color = '#03a68059';
                        return {
                            ...styles,
                            backgroundColor: isDisabled
                                ? null
                                : isSelected
                                    ? '#03a68059'
                                    : isFocused
                                        ? '#03a68059'
                                        : null,
                            color: isDisabled
                                ? '#ccc'
                                : isSelected
                                    ? color > 2
                                        ? '#00374d'
                                        : '#00374d'
                                    : data.color,
                            cursor: isDisabled ? 'not-allowed' : 'default',

                            ':active': {
                                ...styles[':active'],
                                backgroundColor: !isDisabled && (isSelected ? '#03a68059' : '#03a68059'),
                            },
                        };
                    },
                }}
              />
              <span style={{ color: "red" }}>{errors['category']}</span>
            </div>
          </CCol>
          <CCol md={12}>
            <CFormLabel> Add Attachments <span className="text-danger">*</span></CFormLabel>
            {attachmentList?.length > 0 &&
              <div className='d-flex flex-wrap'>
                {attachmentList && attachmentList.map((attachment, index) => {
                  return (
                    <div className="previewPan">
                      <button className='remove-attachment' onClick={(e) => { e.preventDefault(); removeAttachment(attachment._id, index); }} style={{ cursor: "pointer" }}>X</button>
                      <span><img src={attachment.imageUrl} alt="" /></span>
                    </div>
                  )
                })}
              </div>
            }
            <input
              type="file"
              className="form-control custom-file-upload"
              multiple
              accept=".doc,.pdf,.jpg,.jpeg,.png,.xlsx"
              id="addAttachmentsFileUploader"
              ref={uploadAddAttachmentsRef}
              onChange={(e) => { uploadAddAttachments(e) }}
              style={{ display: "none" }}
              name="addAttachments"
            />
            <CButton color="primary" onClick={onClickUploadAttachment}>
              Upload Attachments
            </CButton>
            <div className=''>
              <span style={{ color: "red" }}>{errors['attachments']}</span>
            </div>
          </CCol>
          <CCol md={12}>
            <CFormLabel> Tags <span className="text-danger">*</span></CFormLabel>
            <TagsInput
              value={tags}
              onChange={tagsChange}
              addKeys={[9, 13, 62, 188]}
            />
            <span style={{ color: "red" }}>{errors['tags']}</span>
          </CCol>
          <CCol md={12}>
            <div className='form-group'>
              <CFormLabel> Select Related Blog</CFormLabel>
              <Select
                placeholder={"Select Related Blog"}
                className="wnforSelect"
                name={"blogFilterOption"}
                options={blogOption}
                value={relatedBlog}
                isMulti
                onChange={(data) => handleChangeCategory(data, "BLOG")}
                classNamePrefix="select"
                styles={{
                    option: (styles, { data, isDisabled, isFocused, isSelected }) => {
                        const color = '#03a68059';
                        return {
                            ...styles,
                            backgroundColor: isDisabled
                                ? null
                                : isSelected
                                    ? '#03a68059'
                                    : isFocused
                                        ? '#03a68059'
                                        : null,
                            color: isDisabled
                                ? '#ccc'
                                : isSelected
                                    ? color > 2
                                        ? '#00374d'
                                        : '#00374d'
                                    : data.color,
                            cursor: isDisabled ? 'not-allowed' : 'default',

                            ':active': {
                                ...styles[':active'],
                                backgroundColor: !isDisabled && (isSelected ? '#03a68059' : '#03a68059'),
                            },
                        };
                    },
                }}
              />
            </div>
          </CCol>
          <CCol md={12}>
            <div className='form-group'>
              <CFormLabel> Select Related Infographic</CFormLabel>
              <Select
                placeholder={"Select Related Infographic"}
                className="wnforSelect"
                name={"triviaFilterOption"}
                options={infographicOption}
                value={relatedInfographic}
                isMulti
                onChange={(data) => handleChangeCategory(data, "INFOGRAPIC")}
                classNamePrefix="select"
                styles={{
                    option: (styles, { data, isDisabled, isFocused, isSelected }) => {
                        const color = '#03a68059';
                        return {
                            ...styles,
                            backgroundColor: isDisabled
                                ? null
                                : isSelected
                                    ? '#03a68059'
                                    : isFocused
                                        ? '#03a68059'
                                        : null,
                            color: isDisabled
                                ? '#ccc'
                                : isSelected
                                    ? color > 2
                                        ? '#00374d'
                                        : '#00374d'
                                    : data.color,
                            cursor: isDisabled ? 'not-allowed' : 'default',

                            ':active': {
                                ...styles[':active'],
                                backgroundColor: !isDisabled && (isSelected ? '#03a68059' : '#03a68059'),
                            },
                        };
                    },
                }}
              />
            </div>
          </CCol>

          <hr />

          <CCol md={12}>
            <FormInput
              value={formData.metaTitle}
              label={"Meta Title"}
              name={"metaTitle"}
              onChange={handleChange}
              required={true}
              error={errors['metaTitle']}
            />
          </CCol>

          <CCol md={12}>
            <TextArea
              label={"Meta Description"}
              name="metaDescription"
              value={formData.metaDescription}
              onChange={handleChange}
              required={true}
              error={errors["metaDescription"]}
            />
          </CCol>

          <CCol md={12}>
            <TextArea
              label={"Meta Image Alt"}
              name="metaImageAlt"
              value={formData.metaImageAlt}
              onChange={handleChange}
              required={true}
              error={errors["metaImageAlt"]}
            />
          </CCol>

          <CCol md={12}>
            <CFormLabel>Meta Keywords <span className="text-danger">*</span></CFormLabel>
            <TagsInput
              value={metaKeyWords}
              onChange={metaTagsChange}
              addKeys={[9, 13, 62, 188]}
            />
            <span style={{ color: "red" }}>{errors['metaKeyWords']}</span>
          </CCol>

          <CCol md={12}>
            <CButton color="primary" onClick={handleSubmit} className="d-block" disabled={isButtonDisabled}>
              {type === "CREATE" ? "Create" : "Update"}
            </CButton>
          </CCol>
        </CForm>
      </div>
    </>
  );
}

export default TriviaForm;
